```class Solution {
public:
    string minimizeStringValue(string s) {
        int count[26] = {0}; // Initialize an array to store the count of each letter
        int result = 0; // Initialize the result variable
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == '?') {
                result = INT_MAX; // Set the result to the maximum possible integer value
                for (int j = 0; j < 26; j++) {
                    if (s[i] == '?') {
                        count[j]++;
                        result = min(result, count[j]);
                    }
            }
        }
        return result;
    }
};
```

